import React, { useState } from "react";
import "./PDFAnalyzer.css";

function PDFAnalyzer() {
  const [selectedPDF, setSelectedPDF] = useState("");
  const [sections, setSections] = useState({
    hospitalization: "",
    riskClassifier: "",
    recommendations: "",
    keyInsights: "",
  });
  const [chatContent, setChatContent] = useState("");

  const handleRunAnalysis = async () => {
    try {
      const response = await fetch("http://localhost:8000/analyze-section", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          pdf: selectedPDF,
          section: "all",
        }),
      });
      const data = await response.json();
      setSections({
        summary: data.summary || "",
        hospitalization: data.hospitalization || "",
        riskClassifier: data.riskClassifier || "",
        recommendations: data.recommendations || "",
        keyInsights: data.keyInsights || "",
      });
    } catch (error) {
      console.error("Error fetching analysis:", error);
    }
  };

  const handleChatSubmit = async (e) => {
    e.preventDefault();
    try {
      const response = await fetch("http://localhost:8000/chat-with-document", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          user_input: chatContent,
          document_context: selectedPDF,
        }),
      });
      const data = await response.json();
      setChatContent("");
    } catch (error) {
      console.error("Error sending chat:", error);
    }
  };

  return (
    <div className="analyzer-container">
      <div className="header">
        <h1>IBM WatsonX APS Application</h1>
      </div>

      <div className="controls">
        <select
          className="applicant-select"
          value={selectedPDF}
          onChange={(e) => setSelectedPDF(e.target.value)}
        >
          <option value="">Select an Applicant</option>
          <option value="emily-wilson">Emily Wilson</option>
          <option value="pamela-rogers">Pamela Rogers</option>
        </select>

        <button className="run-button" onClick={handleRunAnalysis}>
          Run Analysis
        </button>
      </div>
      {/* 
      <div className="sections-grid">
        <div className="section-box">
          <h2>Summary</h2>
          <div className="section-content">
            {sections.summary || "No data available"}
          </div>
        </div> */}

      <div className="sections-grid">
        <div className="section-box">
          <h2>Hospitalization</h2>
          <div className="section-content">
            {sections.hospitalization || "No data available"}
          </div>
        </div>

        <div className="section-box">
          <h2>Risk Classifier</h2>
          <div className="section-content">
            {sections.riskClassifier || "No data available"}
          </div>
        </div>

        <div className="section-box">
          <h2>Recommendations</h2>
          <div className="section-content">
            {sections.recommendations || "No data available"}
          </div>
        </div>

        <div className="section-box">
          <h2>Key Insights</h2>
          <div className="section-content">
            {sections.keyInsights || "No data available"}
          </div>
        </div>
      </div>

      <div className="chat-section">
        <h2>Chat with Documents</h2>
        <form onSubmit={handleChatSubmit} className="chat-form">
          <textarea
            className="chat-input"
            value={chatContent}
            onChange={(e) => setChatContent(e.target.value)}
            placeholder="Type your message here..."
          />
          <button type="submit" className="send-button">
            Send
          </button>
        </form>
      </div>
    </div>
  );
}

export default PDFAnalyzer;
